const input = $input.first().json;

const from = input.message?.from || input.callback_query?.from;
const telegramUserId = from?.id;
const messageText = input.message?.text || input.callback_query?.data || '';
const chatId = input.message?.chat?.id || input.callback_query?.message?.chat?.id;

const USER_MAP = {
  1290054454: { name: 'Yianni', calendar: 'jcodis@gmail.com' },
  1075749544: { name: 'Tamta', calendar: 'tammylillystone@gmail.com' },
};

const sender = USER_MAP[telegramUserId] || {
  name: from?.first_name || 'Unknown',
  calendar: null
};

return [{
  json: {
    senderName: sender.name,
    senderCalendar: sender.calendar,
    telegramUserId,
    messageText,
    chatId: String(chatId),
    isKnownUser: !!USER_MAP[telegramUserId]
  }
}];

const events = $input.all();
const senderInfo = $('Identify Sender').first().json;
const now = new Date();

function getCalendarName(email) {
  if (!email) return 'Unknown';
  if (email.includes('tammylillystone')) return 'Tamta (Personal)';
  if (email.includes('jcodis@gmail')) return 'John (Personal)';
  if (email.includes('gwmail.gwu.edu')) return 'John (GWU)';
  if (email.includes('k54kdr8r17632o7mhebt59u9cij53v62')) return 'Tamta (UMich)';
  if (email.includes('kou9jkankc0f09rrt3v8k7g66s')) return 'John (Navy)';
  return email.split('@')[0];
}

const sorted = [...events]
  .filter(e => e.json.summary)
  .sort((a, b) => {
    const aTime = a.json.start?.dateTime || a.json.start?.date || '9999';
    const bTime = b.json.start?.dateTime || b.json.start?.date || '9999';
    return new Date(aTime) - new Date(bTime);
  });

let calendarContext = '';
let currentDay = '';

for (const event of sorted) {
  const e = event.json;
  const eventDate = e.start?.dateTime || e.start?.date;
  if (!eventDate) continue;

  const dayLabel = new Date(eventDate).toLocaleDateString('en-US', {
    weekday: 'long', month: 'short', day: 'numeric',
    timeZone: 'America/Detroit'
  });

  if (dayLabel !== currentDay) {
    currentDay = dayLabel;
    calendarContext += `\n${dayLabel}:\n`;
  }

  let timeStr = 'All day';
  if (e.start?.dateTime) {
    const start = new Date(e.start.dateTime);
    const end = new Date(e.end.dateTime);
    timeStr = start.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: 'America/Detroit' })
      + ' - ' + end.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: 'America/Detroit' });
  }

  const calName = getCalendarName(e.organizer?.email);
  const eventId = e.id || 'unknown';
  calendarContext += `  - ${e.summary} (${timeStr}) [${calName}] {id: ${eventId}}\n`;
}

if (!calendarContext.trim()) {
  calendarContext = 'No events found in the next 30 days.';
}

const currentDate = now.toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  timeZone: 'America/Detroit'
});

return [{
  json: {
    prompt: senderInfo.messageText,
    calendarContext,
    senderName: senderInfo.senderName,
    currentDate,
    chatId: senderInfo.chatId
  }
}];
